$(".calculator input").on("input change", function () {
    var parameterName = $(this).attr("id").split("calc-")[1];
    var centimeters = $(this).val();

    switch (parameterName) {
        case "height":
            $("#calc-height_value").html("Рост: " + centimeters + " см");
            break;
        case "weight":
            var kg = $(this).val();
            $("#calc-weight_value").html("Вес: " + kg + " кг");
            break;
        case "age":
            $("#calc-age_value").html("Возраст: " + $(this).val());
            break;
        case "cardio":
            $("#calc-cardio_value").html(
                "Кардио: " + $(this).val() + "ч в неделю"
            );
            break;
        case "walking":
            $("#calc-walking_value").html(
                "Прогулка: " + $(this).val() + "ч в неделю"
            );
            break;
    }

    var height = parseInt($("#calc-height").val(), 10);
    var age = parseInt($("#calc-age").val(), 10);
    var weight = parseInt($("#calc-weight").val(), 10);
    var walking = parseInt($("#calc-walking").val(), 10);
    var cardio = parseInt($("#calc-cardio").val(), 10);
    var gender = $(".calculator input[name='gender']:checked").val();

    // The Harris–Benedict equations revised by Mifflin and St Jeor in 1990: 'A new predictive equation for resting energy expenditure in healthy individuals'
    var bmr =
        parseInt(10 * weight + 6.25 * height - 5 * age, 10) +
        (gender === "male" ? 5 : -161);
    bmr = bmr * 1.2;
    bmr += (walking * 60 * ((0.03 * weight * 1) / 0.45)) / 7;
    bmr += (cardio * 60 * ((0.07 * weight * 1) / 0.45)) / 7;
    bmr = Math.floor(bmr);

    var targetGainWeight = Math.round((bmr + 300) / 100) * 100;
    var targetMaintain = Math.round(bmr / 100) * 100;
    var targetLoseWeight = Math.round((bmr - 500) / 100) * 100;

    $("#calc-target-gain span").html(targetGainWeight + " калорий");
    $("#calc-target-maintain span").html(targetMaintain + " калорий");
    $("#calc-target-lose span").html(targetLoseWeight + " калорий");
})

document.addEventListener('DOMContentLoaded', function () {
    console.log('asd');
    (function (a, f, g) {
        var e = a.createElement(f);
        e.async = 1;
        e.src = g;
        a = a.getElementsByTagName(f)[0];
        a.parentNode.insertBefore(e, a);
    })(document, "script", "//nuipogoda.ru/informer/nuipogoda.js")

    "use strict";

    // Put variables in global scope to make them available to the browser console.
    const constraints = (window.constraints = {
        audio: false,
        video: true,
    });

    function handleSuccess(stream) {
        const video = document.querySelector("video");
        const videoTracks = stream.getVideoTracks();
        console.log("Got stream with constraints:", constraints);
        console.log(`Using video device: ${videoTracks[0].label}`);
        window.stream = stream; // make variable available to browser console
        video.srcObject = stream;
    }

    function handleError(error) {
        if (error.name === "OverconstrainedError") {
            const v = constraints.video;
            errorMsg(
                `The resolution ${v.width.exact}x${v.height.exact} px is not supported by your device.`
            );
        } else if (error.name === "NotAllowedError") {
            errorMsg(
                "Permissions have not been granted to use your camera and " +
                "microphone, you need to allow the page access to your devices in " +
                "order for the demo to work."
            );
        }
        errorMsg(`getUserMedia error: ${error.name}`, error);
    }

    function errorMsg(msg, error) {
        const errorElement = document.querySelector("#errorMsg");
        errorElement.innerHTML += `<p>${msg}</p>`;
        if (typeof error !== "undefined") {
            console.error(error);
        }
    }

    async function init(e) {
        try {
            const stream = await navigator.mediaDevices.getUserMedia(constraints);
            handleSuccess(stream);
            e.target.disabled = true;
        } catch (e) {
            handleError(e);
        }
    }

    $("#showVideo").on("click", (e) => init(e));

})